import{_ as i,o as l,c as e,a9 as s}from"./chunks/framework.STMWz9Nm.js";const k=JSON.parse('{"title":"持久化与高可用","description":"","frontmatter":{},"headers":[],"relativePath":"语言/java/08-Redis学习/03-持久化与高可用.md","filePath":"语言/java/08-Redis学习/03-持久化与高可用.md","lastUpdated":1776150380000}'),n={name:"语言/java/08-Redis学习/03-持久化与高可用.md"};function h(r,a,t,d,p,c){return l(),e("div",null,[...a[0]||(a[0]=[s(`<h1 id="持久化与高可用" tabindex="-1">持久化与高可用 <a class="header-anchor" href="#持久化与高可用" aria-label="Permalink to “持久化与高可用”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>持久化用于把内存数据保存到磁盘，高可用用于在节点故障时尽量保持 Redis 服务能力。 这两部分决定了 Redis 是否能稳定支撑线上业务。</p><p>一句话理解：</p><ul><li>持久化解决“掉电后数据还能不能回来”</li><li>高可用解决“节点挂了服务还能不能继续”</li></ul><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>如果只会把 Redis 当缓存用，而不了解持久化和高可用，就很难判断：</p><ul><li>数据丢失风险</li><li>故障恢复策略</li><li>主从切换成本</li></ul><p>生产环境里，Redis 不是只追求快，也要考虑稳。</p><h2 id="_3-先建立直觉-主从复制不等于真正高可用" tabindex="-1">3. 先建立直觉：主从复制不等于真正高可用 <a class="header-anchor" href="#_3-先建立直觉-主从复制不等于真正高可用" aria-label="Permalink to “3. 先建立直觉：主从复制不等于真正高可用”">​</a></h2><p>一个很容易误解的点是：</p><ul><li>有主从复制 = 高可用</li></ul><p>其实并不是。 复制只是说明：</p><ul><li>数据在同步</li></ul><p>但高可用还要额外解决：</p><ul><li>故障检测</li><li>角色切换</li><li>客户端流量切换</li><li>复制延迟带来的业务影响</li></ul><h2 id="_4-核心内容" tabindex="-1">4. 核心内容 <a class="header-anchor" href="#_4-核心内容" aria-label="Permalink to “4. 核心内容”">​</a></h2><h3 id="_4-1-rdb" tabindex="-1">4.1 RDB <a class="header-anchor" href="#_4-1-rdb" aria-label="Permalink to “4.1 RDB”">​</a></h3><p>RDB 可以理解成：</p><ul><li>某个时刻把内存快照落盘</li></ul><p>优点：</p><ul><li>恢复速度通常较快</li><li>文件体积通常更适合做备份</li></ul><p>缺点：</p><ul><li>两次快照之间的数据可能丢失</li></ul><h3 id="_4-2-aof" tabindex="-1">4.2 AOF <a class="header-anchor" href="#_4-2-aof" aria-label="Permalink to “4.2 AOF”">​</a></h3><p>AOF 可以理解成：</p><ul><li>按命令追加记录写操作日志</li></ul><p>优点：</p><ul><li>通常数据丢失窗口更小</li></ul><p>缺点：</p><ul><li>文件可能更大</li><li>恢复时要重放日志</li></ul><h3 id="_4-3-混合持久化" tabindex="-1">4.3 混合持久化 <a class="header-anchor" href="#_4-3-混合持久化" aria-label="Permalink to “4.3 混合持久化”">​</a></h3><p>混合持久化的思路可以先粗略理解为：</p><ul><li>结合 RDB 的恢复效率</li><li>和 AOF 的数据完整性优势</li></ul><p>学习阶段先建立这种工程折中意识即可。</p><h3 id="_4-4-主从复制" tabindex="-1">4.4 主从复制 <a class="header-anchor" href="#_4-4-主从复制" aria-label="Permalink to “4.4 主从复制”">​</a></h3><p>Redis 主从复制的核心目标是：</p><ul><li>数据同步</li><li>读扩展</li><li>容灾基础</li></ul><p>但它不直接等于：</p><ul><li>自动故障切换</li></ul><h3 id="_4-5-sentinel" tabindex="-1">4.5 Sentinel <a class="header-anchor" href="#_4-5-sentinel" aria-label="Permalink to “4.5 Sentinel”">​</a></h3><p>Sentinel 主要解决的是：</p><ul><li>主节点故障检测</li><li>主从切换</li><li>配置感知</li></ul><p>学习阶段最重要的理解是：</p><ul><li>Sentinel 关注的是高可用控制层</li><li>它和“单纯有从库”不是一回事</li></ul><h3 id="_4-6-cluster-基础认知" tabindex="-1">4.6 Cluster 基础认知 <a class="header-anchor" href="#_4-6-cluster-基础认知" aria-label="Permalink to “4.6 Cluster 基础认知”">​</a></h3><p>Redis Cluster 更适合解决：</p><ul><li>数据分片</li><li>更大规模容量扩展</li></ul><p>它不只是“多台 Redis”，而是：</p><ul><li>带有槽位和分片语义的集群系统</li></ul><h2 id="_5-学习重点" tabindex="-1">5. 学习重点 <a class="header-anchor" href="#_5-学习重点" aria-label="Permalink to “5. 学习重点”">​</a></h2><p>这一章最重要的是掌握：</p><ul><li>RDB 和 AOF 的核心取舍</li><li>主从复制、Sentinel、Cluster 解决的是不同层次问题</li><li>有复制不等于真正高可用</li><li>恢复速度和数据丢失窗口是持久化设计的核心权衡</li></ul><h2 id="_6-常见问题" tabindex="-1">6. 常见问题 <a class="header-anchor" href="#_6-常见问题" aria-label="Permalink to “6. 常见问题”">​</a></h2><h3 id="_6-1-只关心性能-不关心丢数据风险" tabindex="-1">6.1 只关心性能，不关心丢数据风险 <a class="header-anchor" href="#_6-1-只关心性能-不关心丢数据风险" aria-label="Permalink to “6.1 只关心性能，不关心丢数据风险”">​</a></h3><p>这会让系统表面很快，但可靠性不足。</p><h3 id="_6-2-把主从复制等同于高可用" tabindex="-1">6.2 把主从复制等同于高可用 <a class="header-anchor" href="#_6-2-把主从复制等同于高可用" aria-label="Permalink to “6.2 把主从复制等同于高可用”">​</a></h3><p>复制和高可用不是同一件事。</p><h3 id="_6-3-不理解哨兵和集群的职责差异" tabindex="-1">6.3 不理解哨兵和集群的职责差异 <a class="header-anchor" href="#_6-3-不理解哨兵和集群的职责差异" aria-label="Permalink to “6.3 不理解哨兵和集群的职责差异”">​</a></h3><p>一个偏高可用控制，一个偏分片扩展，不能混为一谈。</p><h2 id="_7-动手验证" tabindex="-1">7. 动手验证 <a class="header-anchor" href="#_7-动手验证" aria-label="Permalink to “7. 动手验证”">​</a></h2><p>这一节我用当前已经跑起来的 Redis 容器做基础验证。</p><h3 id="_7-1-查看当前持久化配置" tabindex="-1">7.1 查看当前持久化配置 <a class="header-anchor" href="#_7-1-查看当前持久化配置" aria-label="Permalink to “7.1 查看当前持久化配置”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-lab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> INFO</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> persistence</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-lab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis-cli</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CONFIG</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> GET</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> appendonly</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> save</span></span></code></pre></div><p>我已经实际看到过类似关键信息：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>aof_enabled:0</span></span>
<span class="line"><span>rdb_last_bgsave_status:ok</span></span>
<span class="line"><span>save</span></span>
<span class="line"><span>3600 1 300 100 60 10000</span></span>
<span class="line"><span>appendonly</span></span>
<span class="line"><span>no</span></span></code></pre></div><p>这些信息说明：</p><ul><li>当前实例启用了基于 <code>save</code> 规则的 RDB 思路</li><li>AOF 当前未开启</li></ul><h3 id="_7-2-你应该观察什么" tabindex="-1">7.2 你应该观察什么 <a class="header-anchor" href="#_7-2-你应该观察什么" aria-label="Permalink to “7.2 你应该观察什么”">​</a></h3><p>重点看：</p><ul><li><code>aof_enabled</code></li><li><code>rdb_last_bgsave_status</code></li><li><code>save</code> 规则</li></ul><p>这些字段能帮助你快速判断：</p><ul><li>当前实例更偏哪种持久化模式</li></ul><h2 id="_8-练习建议" tabindex="-1">8. 练习建议 <a class="header-anchor" href="#_8-练习建议" aria-label="Permalink to “8. 练习建议”">​</a></h2><ul><li>对比 RDB 和 AOF 的适用场景</li><li>画一张 Redis 高可用结构图</li><li>总结常见 Redis 部署模式差异</li><li>用自己的话解释“为什么复制不等于高可用”</li></ul><h2 id="_9-自测问题" tabindex="-1">9. 自测问题 <a class="header-anchor" href="#_9-自测问题" aria-label="Permalink to “9. 自测问题”">​</a></h2><ul><li>RDB 和 AOF 各有什么优缺点？</li><li>Sentinel 主要解决什么问题？</li><li>Redis Cluster 更适合解决什么类型需求？</li><li>为什么“有复制”不等于“高可用”？</li></ul><h2 id="_10-自测核对要点" tabindex="-1">10. 自测核对要点 <a class="header-anchor" href="#_10-自测核对要点" aria-label="Permalink to “10. 自测核对要点”">​</a></h2><ul><li>RDB 偏快照，AOF 偏日志</li><li>持久化设计核心在于恢复速度与数据丢失窗口的权衡</li><li>主从复制提供同步基础，不自动等于高可用</li><li>Sentinel 和 Cluster 分别解决不同层面的系统问题</li></ul>`,79)])])}const _=i(n,[["render",h]]);export{k as __pageData,_ as default};
